const TESTI_API_BASE = "https://alexokoriengobe.onrender.com/api/testimonials";
async function refreshAccessToken() {
  try {
    const t = await fetch(
      "https://alexokoriengobe.onrender.com/api/auth/refresh-token",
      {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
      },
    );
    if (t.ok) {
      const e = await t.json();
      if (e.accessToken)
        return (localStorage.setItem("token", e.accessToken), e.accessToken);
    }
    return (
      localStorage.removeItem("token"),
      (window.location.href = "../login/index.html"),
      null
    );
  } catch (t) {
    return (
      localStorage.removeItem("token"),
      (window.location.href = "../login/index.html"),
      null
    );
  }
}
async function authFetch(t, e = {}) {
  let n = localStorage.getItem("token");
  ((e.headers = e.headers || {}),
    n && (e.headers.Authorization = `Bearer ${n}`));
  let o = await fetch(t, e);
  return (
    (401 !== o.status && 403 !== o.status) ||
      ((n = await refreshAccessToken()),
      n &&
        ((e.headers.Authorization = `Bearer ${n}`), (o = await fetch(t, e)))),
    o
  );
}
async function loadTestimonials() {
  const t = await authFetch(`${TESTI_API_BASE}/getAllTesti`),
    e = await t.json(),
    n = document.getElementById("testimonials-list");
  n &&
    ((n.innerHTML = ""),
    (e.testimonials || []).forEach((t) => {
      const e = document.createElement("div");
      ((e.className = "testimonial-card"),
        (e.innerHTML = `\n      <img src="${t.userImage}" alt="User" style="width:60px;height:60px;border-radius:50%;object-fit:cover;">\n      <div class="testimonial-content">\n        <div class="testimonial-text">${t.text}</div>\n        <div class="testimonial-meta">\n          <span class="testimonial-name">${t.name}</span> |\n          <span class="testimonial-location">${t.location}</span>\n        </div>\n        <div class="testimonial-actions">\n          <button class="edit-btn">Edit</button>\n          <button class="delete-btn">Delete</button>\n        </div>\n      </div>\n    `),
        (e.querySelector(".delete-btn").onclick = () => showDeleteModal(t._id)),
        (e.querySelector(".edit-btn").onclick = () => openEditModal(t)),
        n.appendChild(e));
    }));
}
document.addEventListener("DOMContentLoaded", () => {
  loadTestimonials();
});
const testimonialForm = document.getElementById("testimonial-form");
if (testimonialForm) {
  const t = testimonialForm.querySelector('button[type="submit"]');
  testimonialForm.onsubmit = async function (e) {
    if ((e.preventDefault(), t)) {
      t.disabled = !0;
      t.textContent;
      t.textContent = "Uploading...";
    }
    const n = new FormData(this);
    try {
      (await authFetch(`${TESTI_API_BASE}/addTesti`, {
        method: "POST",
        body: n,
      }),
        this.reset(),
        loadTestimonials());
    } catch (t) {
      showToast("Upload failed. Please try again.", "error");
    } finally {
      t && ((t.disabled = !1), (t.textContent = "Add Testimonial"));
    }
  };
}
